'use client'

import { useState, useEffect, useCallback } from 'react'
import { useAuth } from '@/context/AuthContext'
import { Wallet, ArrowUpRight, ArrowDownRight, Gift, Clock, Search, Send, Briefcase } from 'lucide-react'
import clsx from 'clsx'

interface Transaction {
  id: string
  from_user_id: string | null
  to_user_id: string | null
  amount: number
  type: string
  description: string
  created: string
}

export default function Bank() {
  const { profile, roles, user, refreshProfile } = useAuth()
  const [activeTab, setActiveTab] = useState<'send' | 'history' | 'daily' | 'inventory'>('send')
  const [recipient, setRecipient] = useState('')
  const [recipientSuggestions, setRecipientSuggestions] = useState<any[]>([])
  const [showSuggestions, setShowSuggestions] = useState(false)
  const [amount, setAmount] = useState('')
  const [loading, setLoading] = useState(false)
  const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null)
  const [transactions, setTransactions] = useState<Transaction[]>([])
  const [inventory, setInventory] = useState<any[]>([])

  const loadInventory = useCallback(async () => {
    if (!profile?.id) return
    try {
      const response = await fetch('/api/bank/inventory')
      const data = await response.json()
      if (data.items) setInventory(data.items)
    } catch (error) {
      console.error('Error loading inventory:', error)
    }
  }, [profile?.id])

  const loadTransactions = useCallback(async () => {
    if (!profile?.id) return
    try {
      const response = await fetch('/api/bank/transactions')
      const data = await response.json()
      if (data.items) {
        setTransactions(data.items as Transaction[])
      }
    } catch (error) {
      console.error('Error loading transactions:', error)
    }
  }, [profile?.id])

  useEffect(() => {
    if (profile?.id) {
      loadTransactions()
      loadInventory()
    }
  }, [profile?.id, loadTransactions, loadInventory])

  // ÔöÇÔöÇ Autocomplete Search ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
  useEffect(() => {
    const searchUsers = async () => {
      if (recipient.length < 2) {
        setRecipientSuggestions([])
        return
      }

      // If recipient was selected from suggestion, don't search again
      if (recipientSuggestions.some(s => s.username === recipient || s.discord_id === recipient)) {
        return
      }

      try {
        const res = await fetch(`/api/bank/search-users?q=${encodeURIComponent(recipient)}`)
        const data = await res.json()
        setRecipientSuggestions(data.users || [])
        setShowSuggestions(true)
      } catch (err) {
        console.error('Search error:', err)
      }
    }

    const timer = setTimeout(searchUsers, 300)
    return () => clearTimeout(timer)
  }, [recipient])

  const canClaimDaily = () => {
    if (!profile?.last_daily) return true
    const lastClaim = new Date(profile.last_daily)
    const now = new Date()
    const diff = now.getTime() - lastClaim.getTime()
    const hours = diff / (1000 * 60 * 60)
    return hours >= 24
  }

  const getTimeUntilDaily = () => {
    if (!profile?.last_daily) return 'Disponible'
    const lastClaim = new Date(profile.last_daily)
    const nextClaim = new Date(lastClaim.getTime() + 24 * 60 * 60 * 1000)
    const now = new Date()
    const diff = nextClaim.getTime() - now.getTime()
    if (diff <= 0) return 'Disponible'
    const hours = Math.floor(diff / (1000 * 60 * 60))
    const minutes = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60))
    return `${hours}h ${minutes}min`
  }

  const handleTransfer = async () => {
    if (!recipient || !amount || parseFloat(amount) <= 0) {
      setMessage({ type: 'error', text: 'Veuillez entrer un montant valide' })
      return
    }

    if (parseFloat(amount) > (profile?.balance || 0)) {
      setMessage({ type: 'error', text: 'Solde insuffisant' })
      return
    }

    setLoading(true)
    setMessage(null)

    try {
      const response = await fetch('/api/bank/transactions', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          action: 'transfer',
          amount: parseFloat(amount),
          recipient
        })
      })

      const data = await response.json()

      if (response.ok) {
        setMessage({ type: 'success', text: `Transfert de ${amount}Ôé¼ effectu├® avec succ├¿s !` })
        setRecipient('')
        setAmount('')
        setRecipientSuggestions([])
        await refreshProfile()
        await loadTransactions()
      } else {
        setMessage({ type: 'error', text: data.error || 'Une erreur est survenue' })
      }
    } catch (error) {
      setMessage({ type: 'error', text: 'Erreur de connexion au serveur' })
    } finally {
      setLoading(false)
    }
  }

  const handleClaimDaily = async () => {
    setLoading(true)
    setMessage(null)

    try {
      const response = await fetch('/api/bank/transactions', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'daily' })
      })

      const data = await response.json()

      if (response.ok) {
        setMessage({ type: 'success', text: 'R├®compense quotidienne r├®cup├®r├®e (+50Ôé¼) !' })
        await refreshProfile()
        await loadTransactions()
      } else {
        setMessage({ type: 'error', text: data.error || 'Une erreur est survenue' })
      }
    } catch (error) {
      setMessage({ type: 'error', text: 'Erreur de connexion au serveur' })
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="page-container">
      {/* Header */}
      <div className="animate-slideIn">
        <h1 className="text-4xl font-black text-white tracking-tight">Banque</h1>
        <p className="text-discord-muted mt-1 font-medium">G├®rez vos finances LunaVerse</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Sidebar / Tabs */}
        <div className="lg:col-span-1 space-y-4">
          <div className="glass-card p-2 space-y-1">
            <button
              onClick={() => setActiveTab('send')}
              className={clsx(
                "w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-300 font-bold text-sm",
                activeTab === 'send' ? "bg-discord-blurple text-white shadow-lg shadow-discord-blurple/20" : "text-discord-muted hover:bg-white/5"
              )}
            >
              <Send className="w-5 h-5" />
              Transf├®rer
            </button>
            <button
              onClick={() => setActiveTab('inventory')}
              className={clsx(
                "w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-300 font-bold text-sm",
                activeTab === 'inventory' ? "bg-purple-500 text-white shadow-lg shadow-purple-500/20" : "text-discord-muted hover:bg-white/5"
              )}
            >
              <Briefcase className="w-5 h-5" />
              Mon Inventaire
            </button>
            <button
              onClick={() => setActiveTab('daily')}
              className={clsx(
                "w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-300 font-bold text-sm",
                activeTab === 'daily' ? "bg-discord-success text-discord-darker shadow-lg shadow-discord-success/20" : "text-discord-muted hover:bg-white/5"
              )}
            >
              <Gift className="w-5 h-5" />
              R├®compenses
            </button>
            <button
              onClick={() => setActiveTab('history')}
              className={clsx(
                "w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-300 font-bold text-sm",
                activeTab === 'history' ? "bg-white/10 text-white" : "text-discord-muted hover:bg-white/5"
              )}
            >
              <Clock className="w-5 h-5" />
              Historique
            </button>
          </div>

          {/* Credit Card Visual */}
          <div className="relative h-48 w-full rounded-2xl overflow-hidden p-6 text-white group shadow-xl transition-transform hover:-translate-y-1" style={{ background: 'linear-gradient(135deg, #5865F2, #3b42a0)', boxShadow: '0 15px 35px rgba(88,101,242,0.3)' }}>
            {/* Background elements */}
            <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full blur-2xl origin-top-right scale-150 transform-gpu group-hover:scale-110 transition-transform duration-700" />
            <div className="absolute -bottom-8 -left-8 w-24 h-24 bg-purple-500/30 rounded-full blur-xl" />
            
            <div className="relative z-10 flex flex-col h-full justify-between">
              <div className="flex justify-between items-start">
                <div>
                  <p className="text-[10px] uppercase tracking-widest text-white/70 font-bold mb-0.5">Solde LunaVerse</p>
                  <p className="text-3xl font-black">{profile?.balance.toFixed(2)} Ôé¼</p>
                </div>
                <div className="text-white/60">
                  <Wallet className="w-8 h-8" />
                </div>
              </div>
              
              <div>
                <p className="font-mono text-lg tracking-[0.2em] opacity-80 mb-1">
                  **** **** **** {(profile?.discord_id || '0000').slice(-4)}
                </p>
                <div className="flex justify-between items-end">
                  <p className="text-sm font-bold uppercase tracking-wider">{profile?.username || 'Utilisateur'}</p>
                  <p className="text-xs font-black italic">LUNA CARD</p>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Main Content */}
        <div className="lg:col-span-2">
          {activeTab === 'send' && (
            <div className="glass-card animate-fadeIn">
              <h3 className="text-xl font-black text-white mb-6">Nouveau transfert</h3>
              <div className="space-y-4">
                <div>
                  <label className="text-xs font-black text-discord-muted uppercase tracking-widest mb-2 block">Destinataire</label>
                  <div className="relative group">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-discord-muted group-focus-within:text-discord-blurple transition-colors" />
                    <input
                      type="text"
                      placeholder="Nom d'utilisateur ou ID Discord"
                      className="glass-input w-full pl-12"
                      value={recipient}
                      onChange={(e) => setRecipient(e.target.value)}
                      onFocus={() => recipientSuggestions.length > 0 && setShowSuggestions(true)}
                    />
                    
                    {/* Autocomplete Suggestions */}
                    {showSuggestions && recipientSuggestions.length > 0 && (
                      <div className="absolute top-full left-0 right-0 mt-2 glass-card p-2 z-50 animate-fadeIn space-y-1 shadow-2xl ring-1 ring-white/10">
                        {recipientSuggestions.map((suggestion) => (
                          <button
                            key={suggestion.id}
                            onClick={() => {
                              setRecipient(suggestion.username)
                              setShowSuggestions(false)
                            }}
                            className="w-full flex items-center gap-3 p-2 rounded-xl hover:bg-white/5 transition-colors text-left group"
                          >
                            <div className="w-8 h-8 rounded-lg overflow-hidden bg-white/10 ring-1 ring-white/10">
                              {suggestion.avatar_url ? (
                                <img src={suggestion.avatar_url} alt="" className="w-full h-full object-cover" />
                              ) : (
                                <div className="w-full h-full flex items-center justify-center text-[10px] font-black text-discord-muted uppercase">
                                  {suggestion.username.substring(0, 2)}
                                </div>
                              )}
                            </div>
                            <div className="flex-1 min-w-0">
                              <p className="text-sm font-black text-white truncate group-hover:text-discord-blurple transition-colors">
                                {suggestion.username}
                              </p>
                              <p className="text-[10px] font-bold text-discord-muted uppercase tracking-widest truncate">
                                {suggestion.discord_id}
                              </p>
                            </div>
                          </button>
                        ))}
                      </div>
                    )}

                    {/* Click away listener to close suggestions */}
                    {showSuggestions && (
                      <div 
                        className="fixed inset-0 z-40" 
                        onClick={() => setShowSuggestions(false)}
                      />
                    )}
                  </div>
                </div>
                <div>
                  <label className="text-xs font-black text-discord-muted uppercase tracking-widest mb-2 block">Montant</label>
                  <div className="relative group">
                    <Wallet className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-discord-muted group-focus-within:text-discord-blurple transition-colors" />
                    <input
                      type="number"
                      placeholder="0.00"
                      className="glass-input w-full pl-12"
                      value={amount}
                      onChange={(e) => setAmount(e.target.value)}
                    />
                  </div>
                </div>

                {message && (
                  <div className={clsx(
                    "p-4 rounded-xl text-sm font-bold animate-fadeIn",
                    message.type === 'success' ? "bg-discord-success/10 text-discord-success border border-discord-success/20" : "bg-discord-error/10 text-discord-error border border-discord-error/20"
                  )}>
                    {message.text}
                  </div>
                )}

                <button
                  onClick={handleTransfer}
                  disabled={loading}
                  className="btn btn-primary w-full py-4 text-lg mt-4"
                >
                  {loading ? 'Traitement...' : 'Confirmer le transfert'}
                </button>
              </div>
            </div>
          )}

          {activeTab === 'daily' && (
            <div className="glass-card animate-fadeIn">
              <h3 className="text-xl font-black text-white mb-6">R├®compenses disponibles</h3>
              <div className="space-y-4">
                <div className="p-6 rounded-2xl bg-white/5 border border-white/5 flex items-center justify-between group">
                  <div className="flex items-center gap-4">
                    <div className="w-12 h-12 bg-discord-success/20 rounded-xl flex items-center justify-center group-hover:bg-discord-success transition-colors">
                      <Gift className="w-6 h-6 text-discord-success group-hover:text-discord-darker" />
                    </div>
                    <div>
                      <p className="text-white font-black">R├®compense Quotidienne</p>
                      <p className="text-xs text-discord-muted font-bold uppercase tracking-widest">
                        {canClaimDaily() ? 'Pr├¬t ├á ├¬tre r├®cup├®r├®' : `Prochain dans ${getTimeUntilDaily()}`}
                      </p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-2xl font-black text-white mb-2">+50Ôé¼</p>
                    <button
                      onClick={handleClaimDaily}
                      disabled={!canClaimDaily() || loading}
                      className={clsx(
                        "btn btn-sm",
                        canClaimDaily() ? "btn-success" : "btn-ghost opacity-50"
                      )}
                    >
                      {canClaimDaily() ? 'R├®clamer' : 'Attendre'}
                    </button>
                  </div>
                </div>
              </div>
            </div>
          )}

          {activeTab === 'inventory' && (
             <div className="glass-card animate-fadeIn">
               <h3 className="text-xl font-black text-white mb-6">Votre inventaire</h3>
               {inventory.length === 0 ? (
                 <div className="p-12 text-center border border-dashed border-white/10 rounded-2xl">
                   <Briefcase className="w-12 h-12 text-discord-muted opacity-50 mx-auto mb-4" />
                   <p className="text-discord-muted font-bold text-lg mb-1">Votre inventaire est vide.</p>
                   <p className="text-sm text-discord-muted opacity-70">Achetez des objets dans la boutique !</p>
                 </div>
               ) : (
                 <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4">
                   {inventory.map(item => (
                     <div key={item.id} className="relative p-4 rounded-2xl bg-white/5 border border-white/10 hover:border-discord-blurple/50 hover:bg-white/10 transition-colors group">
                       <div className="absolute top-2 right-2 bg-discord-blurple text-white text-[10px] font-black px-2 py-0.5 rounded-full shadow-md">
                         x{item.count}
                       </div>
                       <div className="text-3xl mb-3 text-center">
                         {item.type === 'food' ? '­ƒìò' : item.type === 'medication' ? '­ƒÆè' : '­ƒÄü'}
                       </div>
                       <p className="text-sm font-black text-white text-center leading-tight mb-1">{item.name}</p>
                       <p className="text-[10px] font-bold text-discord-muted uppercase tracking-widest text-center">{item.type || 'Objet'}</p>
                     </div>
                   ))}
                 </div>
               )}
             </div>
          )}

          {activeTab === 'history' && (
            <div className="glass-card animate-fadeIn p-2">
              <h3 className="text-xl font-black text-white px-4 py-4">Historique des transactions</h3>
              <div className="space-y-1">
                 {transactions.length > 0 ? (
                  transactions.map((tx) => {
                    const isOutbound = tx.from_user_id === profile?.id
                    return (
                      <div key={tx.id} className="flex items-center gap-4 p-4 hover:bg-white/5 rounded-2xl transition-colors group">
                        <div className={clsx(
                          "w-12 h-12 rounded-2xl flex items-center justify-center transition-transform group-hover:scale-110",
                          !isOutbound ? "bg-discord-success/20 text-discord-success" : "bg-discord-error/20 text-discord-error"
                        )}>
                          {!isOutbound ? <ArrowDownRight className="w-6 h-6" /> : <ArrowUpRight className="w-6 h-6" />}
                        </div>
                        <div className="flex-1 min-w-0">
                          <p className="text-white font-bold truncate">{tx.description}</p>
                          <p className="text-[10px] font-black text-discord-muted uppercase tracking-[0.2em]">
                            {new Date(tx.created).toLocaleDateString('fr-FR', { day: 'numeric', month: 'long', hour: '2-digit', minute: '2-digit' })}
                          </p>
                        </div>
                        <div className="text-right">
                          <p className={clsx(
                            "text-lg font-black",
                            !isOutbound ? "text-discord-success" : "text-discord-error"
                          )}>
                            {!isOutbound ? '+' : '-'}{tx.amount.toFixed(0)} Ôé¼
                          </p>
                          <p className="text-[10px] font-black text-discord-muted uppercase tracking-widest">{tx.type}</p>
                        </div>
                      </div>
                    )
                  })
                ) : (
                  <div className="p-12 text-center">
                    <p className="text-discord-muted font-medium">Aucune transaction trouv├®e.</p>
                  </div>
                )}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  )
}

'use client'

import { useState, useEffect } from 'react'
import { Heart, X, Flame, Search, MessageCircle, AlertCircle } from 'lucide-react'
import { useAuth } from '@/context/AuthContext'
import clsx from 'clsx'

interface DatingProfile {
  id: string
  username: string
  avatar_url: string
  discord_id: string
  bio?: string
  age?: number
}

export default function Dating() {
  const { profile } = useAuth()
  const [profiles, setProfiles] = useState<DatingProfile[]>([])
  const [currentIndex, setCurrentIndex] = useState(0)
  const [loading, setLoading] = useState(true)
  const [matchAnimation, setMatchAnimation] = useState<DatingProfile | null>(null)

  useEffect(() => {
    // Simulated fetching for the dating app
    const fetchProfiles = async () => {
      setLoading(true)
      setTimeout(() => {
        setProfiles([
          { id: 'p1', username: 'Alex', avatar_url: '', discord_id: '123', age: 20, bio: 'J\'aime la musique et les balades en for├¬t.' },
          { id: 'p2', username: 'Sam', avatar_url: '', discord_id: '456', age: 22, bio: 'Gamer passionn├®, on joue quand ?' },
          { id: 'p3', username: 'Charlie', avatar_url: '', discord_id: '789', age: 21, bio: 'Toujours partante pour un caf├® !' }
        ])
        setLoading(false)
      }, 1000)
    }

    if (profile?.id) {
      fetchProfiles()
    }
  }, [profile?.id])

  const handleSwipe = async (direction: 'left' | 'right') => {
    if (currentIndex >= profiles.length) return

    const currentProfile = profiles[currentIndex]
    setCurrentIndex(prev => prev + 1)

    if (direction === 'right') {
      // Logic to save the like (Call to /api/dating/swipe would happen here)

      // Simulate a Match occasionally!
      if (Math.random() > 0.5) {
        setMatchAnimation(currentProfile)
        setTimeout(() => setMatchAnimation(null), 3000)
      }
    }
  }

  const currentProfile = profiles[currentIndex]

  return (
    <div className="page-container h-[calc(100vh-80px)] overflow-hidden flex flex-col relative">
      <div className="text-center mb-6 animate-slideIn">
        <h1 className="text-3xl font-black text-rose-500 flex items-center justify-center gap-2 tracking-tight">
          <Flame className="w-8 h-8 fill-rose-500" /> Luna Match
        </h1>
        <p className="text-discord-muted text-sm mt-1 uppercase tracking-widest font-bold">Trouvez votre moiti├® RP</p>
      </div>

      {matchAnimation && (
        <div className="absolute inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-fadeIn">
          <div className="text-center p-8 animate-bounce">
            <h2 className="text-6xl font-black text-transparent bg-clip-text bg-gradient-to-r from-rose-400 to-pink-500 mb-4 italic tracking-tighter">
              C&apos;EST UN MATCH !
            </h2>
            <p className="text-xl text-white font-bold mb-8">Vous et {matchAnimation.username} vous plaisez mutuellement.</p>
            <button className="btn bg-rose-500 hover:bg-rose-600 text-white font-black py-4 px-8 rounded-full shadow-lg shadow-rose-500/50 flex items-center gap-3 mx-auto">
              <MessageCircle className="w-5 h-5" /> Envoyer un message
            </button>
          </div>
          {/* Confetti simulation using CSS would go here */}
        </div>
      )}

      {loading ? (
        <div className="flex-1 flex flex-col items-center justify-center">
          <div className="w-24 h-24 relative animate-pulse mb-6">
            <Heart className="w-full h-full text-rose-500/20" />
            <Search className="w-10 h-10 text-rose-500 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 animate-bounce" />
          </div>
          <p className="font-bold text-discord-muted uppercase tracking-widest animate-pulse">Recherche en cours...</p>
        </div>
      ) : currentProfile ? (
        <div className="flex-1 flex flex-col items-center max-w-sm mx-auto w-full relative h-[60vh] max-h-[600px] perspective-1000">

          <div className="w-full h-[85%] relative preserve-3d shadow-2xl shadow-rose-500/10 rounded-3xl overflow-hidden glass-card transition-transform duration-500 hover:scale-[1.02]">
            {/* Image Placeholder */}
            {currentProfile.avatar_url ? (
               <img src={currentProfile.avatar_url} alt={currentProfile.username} className="w-full h-full object-cover" />
            ) : (
               <div className="w-full h-full bg-gradient-to-b from-rose-500/20 to-purple-800/40 flex items-center justify-center text-rose-500/50">
                 <Heart className="w-32 h-32" />
               </div>
            )}

            <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/40 to-transparent" />

            <div className="absolute bottom-0 left-0 w-full p-6 text-white">
              <h2 className="text-4xl font-black mb-1 flex items-end gap-2">
                {currentProfile.username} 
                {currentProfile.age && <span className="text-xl font-normal text-white/80">{currentProfile.age}</span>}
              </h2>
              <div className="flex items-center gap-2 mb-3 text-sm text-rose-200">
                <AlertCircle className="w-4 h-4" /> RP Uniquement
              </div>
              {currentProfile.bio && (
                <p className="text-white/80 font-medium leading-relaxed">{currentProfile.bio}</p>
              )}
            </div>
          </div>

